		diags = diags.Append(tfdiags.Sourceless(
			tfdiags.Error,
			"Unsupported plan mode",
			"Forgetting all resources is only allowed in the context of a destroy plan. This is a bug in Terraform, please report it.",
		))
		return nil, nil, diags
	}

