	diags = diags.Append(ctx.Hook(func(h Hook) (HookAction, error) {
		return h.PostDiff(n.HookResourceIdentity(), addrs.NotDeposed, action, priorVal, plannedNewVal)
	}))
	if diags.HasErrors() {
		return nil, nil, deferred, keyData, diags
	}

